module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const palette = ['#3b82f6', '#f59e0b', '#22c55e', '#ef4444', '#8b5cf6', '#06b6d4', '#64748b'];
const custom = String(args.colors || '').split(',').map((x) => x.trim()).filter(Boolean);
const pal = custom.length ? custom : palette;
const normalize = String(args.normalize) === 'true';
const showVals = String(args.showvalues === undefined ? 'true' : args.showvalues) !== 'false';
const unit = esc(args.unit || '');
const heightRaw = parseFloat(args.height);
const height = Number.isFinite(heightRaw) ? Math.max(10, Math.min(80, heightRaw)) : 30;
const bars = [];
sections.join('\n').split('\n').map((l) => l.trim()).filter(Boolean).forEach((l) => {
  const i = l.indexOf('|');
  if (i < 0) return;
  const vals = l.slice(i + 1).trim().split(/[\s,]+/).map(parseFloat).filter((x) => Number.isFinite(x) && x >= 0);
  if (vals.length) bars.push({ label: l.slice(0, i).trim(), vals });
});
if (!bars.length) return `<div>(stackedbar: lines like "Label | 30 45 25")</div>`;
const maxTotal = Math.max(...bars.map((b) => b.vals.reduce((a, x) => a + x, 0))) || 1;
let html = `\n\n<div class="mdp-mod-stackedbar" style="--sb-h:${height}px;">`;
bars.forEach((b) => {
  const total = b.vals.reduce((a, x) => a + x, 0) || 1;
  const scale = normalize ? 100 / total : 100 / maxTotal;
  html += `<div class="mdp-sb-row"><div class="mdp-sb-label">${esc(b.label)}</div><div class="mdp-sb-bar">`;
  b.vals.forEach((v, i) => {
    const w = v * scale;
    html += `<div class="mdp-sb-seg" style="width:${w.toFixed(2)}%; background:${pal[i % pal.length]};">` +
      (showVals && w >= 9 ? `<span>${+v.toFixed(2)}${unit}</span>` : '') + `</div>`;
  });
  html += `</div></div>`;
});
const names = String(args.series || '').split(',').map((x) => x.trim()).filter(Boolean);
if (names.length) {
  html += `<div class="mdp-sb-legend">` + names.map((nm, i) =>
    `<span><i style="background:${pal[i % pal.length]};"></i>${esc(nm)}</span>`).join('') + `</div>`;
}
html += `</div>\n\n`;
return html;
